@prefix cdif: <https://cdif.org/0.1/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/vd/age-years> ;
            sh:resultMessage "A cdif:SubstantiveValueDomain should carry a cdif:displayLabel (human-readable label)" ;
            sh:resultPath cdif:displayLabel ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:datatype xsd:string ;
                    sh:message "A cdif:SubstantiveValueDomain should carry a cdif:displayLabel (human-readable label)" ;
                    sh:minCount 1 ;
                    sh:path cdif:displayLabel ;
                    sh:severity sh:Warning ] ] .

